def classify_data(data):
 if isinstance(data, (int, float)):
 return 'numerical'
 elif isinstance(data, str):
 return 'categorical'
 else:
 return 'unknown'

# Example usage:
data = 123
print(classify_data(data)) # Output: numerical
data = 'hello'
print(classify_data(data)) # Output: categorical

#include <stdio.h>

char* classify_data(void* data) {
 if (data == (int*)data) {
 return 'numerical';
 } else if (data == (char*)data) {
 return 'categorical';
 } else {
 return 'unknown';
 }
}

int main() {
 int data = 123;
 printf('%s\n', classify_data(&data)); // Output: numerical
 char* str = 'hello';
 printf('%s\n', classify_data(str)); // Output: categorical
 return 0;
}
